<script setup lang="ts">
import { onMounted, reactive, ref } from "vue";
import { ElMessage, ElMessageBox } from "element-plus";
import { api, type DirectModel, type ProviderCredential, type ProviderSummary } from "../api";
const providers = ref<ProviderSummary[]>([]); const models = ref<DirectModel[]>([]); const credentials = ref<ProviderCredential[]>([]); const selected = ref<ProviderSummary | null>(null); const loading = ref(false); const dialog = ref<"provider" | "credential" | "model" | null>(null); const editingProvider = ref<ProviderSummary | null>(null); const editingModel = ref<DirectModel | null>(null);
const providerForm = reactive({ name: "", providerType: "OPENAI_COMPATIBLE", baseUrl: "", enabled: true }); const credentialForm = reactive({ name: "", apiKey: "", enabled: true }); const modelForm = reactive({ providerId: 0, modelName: "", enabled: true, inputPricePerMillion: 0, outputPricePerMillion: 0, currency: "USD" });
async function load() { loading.value = true; try { const [providerData, modelData] = await Promise.all([api.providers({ page: 0, size: 100 }), api.directModels()]); providers.value = providerData.items; models.value = modelData.items; if (selected.value) await openDetail(providers.value.find(item => item.providerId === selected.value?.providerId) ?? null); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "模型目录加载失败"); } finally { loading.value = false; } }
async function openDetail(provider: ProviderSummary | null) { selected.value = provider; credentials.value = provider ? (await api.credentials(provider.providerId)).items : []; }
function openProvider(provider?: ProviderSummary) { editingProvider.value = provider ?? null; Object.assign(providerForm, provider ? { name: provider.name, providerType: provider.providerType, baseUrl: provider.baseUrl ?? "", enabled: provider.enabled } : { name: "", providerType: "OPENAI_COMPATIBLE", baseUrl: "", enabled: true }); dialog.value = "provider"; }
function openCredential() { Object.assign(credentialForm, { name: "", apiKey: "", enabled: true }); dialog.value = "credential"; }
function openModel(model?: DirectModel) { editingModel.value = model ?? null; Object.assign(modelForm, model ? model : { providerId: selected.value?.providerId ?? 0, modelName: "", enabled: true, inputPricePerMillion: 0, outputPricePerMillion: 0, currency: "USD" }); dialog.value = "model"; }
async function saveProvider() { try { if (editingProvider.value) await api.updateProvider(editingProvider.value.providerId, providerForm); else await api.createProvider(providerForm); dialog.value = null; await load(); ElMessage.success("Provider 已保存"); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "保存失败"); } }
async function saveCredential() { if (!selected.value) return; try { await api.createCredential(selected.value.providerId, credentialForm); dialog.value = null; await openDetail(selected.value); ElMessage.success("凭据已加密保存，明文不会再次显示"); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "保存失败"); } }
async function saveModel() { try { if (editingModel.value) await api.updateDirectModel(editingModel.value.modelId, modelForm); else await api.createDirectModel(modelForm); dialog.value = null; await load(); ElMessage.success("真实模型已保存"); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "保存失败"); } }
async function disableCredential(item: ProviderCredential) { try { await ElMessageBox.confirm(`停用 ${item.name} 后不会再被网关选中。`, "确认停用凭据", { type: "warning" }); await api.disableCredential(item.credentialId); if (selected.value) await openDetail(selected.value); } catch (error) { if (error !== "cancel" && error !== "close") ElMessage.error(error instanceof Error ? error.message : "停用失败"); } }
async function removeModel(item: DirectModel) { try { await ElMessageBox.confirm(`删除 ${item.modelName} 前必须先移除团队授权。`, "确认删除模型", { type: "warning" }); await api.deleteDirectModel(item.modelId); await load(); } catch (error) { if (error !== "cancel" && error !== "close") ElMessage.error(error instanceof Error ? error.message : "删除失败"); } }
onMounted(load);
</script>
<template><section class="page-stack" v-loading="loading"><header class="page-heading"><div><p class="eyebrow">Direct provider catalog</p><h1>模型供应商</h1><p>调用方直接使用真实模型名；同一 Provider 可维护多把加密 API Key，由网关轮询并在首包前故障切换。</p></div><el-button type="primary" @click="openProvider()">新增 Provider</el-button></header><section class="two-column"><section class="surface"><div class="section-title"><h2>Provider</h2></div><div class="compact-list"><button v-for="provider in providers" :key="provider.providerId" class="list-row" :class="{ selected: selected?.providerId === provider.providerId }" @click="openDetail(provider)"><strong>{{ provider.name }}</strong><small>{{ provider.providerType }} · {{ provider.baseUrl || '本地 Mock' }}</small></button></div></section><section class="surface"><template v-if="selected"><div class="section-title"><div><h2>{{ selected.name }}</h2><p class="muted">{{ selected.providerType }} · {{ selected.baseUrl || '本地 Mock Provider' }}</p></div><el-button @click="openProvider(selected)">编辑</el-button></div><div class="detail-block"><div class="section-title"><h3>凭据池</h3><el-button type="primary" plain @click="openCredential" :disabled="selected.providerType !== 'OPENAI_COMPATIBLE'">新增 API Key</el-button></div><el-table :data="credentials" size="small"><el-table-column prop="name" label="名称"/><el-table-column label="末四位"><template #default="scope">••••{{ scope.row.lastFour }}</template></el-table-column><el-table-column label="状态"><template #default="scope"><el-tag :type="scope.row.enabled ? 'success' : 'info'">{{ scope.row.enabled ? '启用' : '停用' }}</el-tag></template></el-table-column><el-table-column label="操作" width="80"><template #default="scope"><el-button v-if="scope.row.enabled" text type="danger" @click="disableCredential(scope.row)">停用</el-button></template></el-table-column></el-table><p v-if="selected.providerType === 'MOCK_OPENAI'" class="muted">Mock Provider 不保存外部 API Key，可用于本地验证与故障演练。</p></div></template><template v-else><h2>选择一个 Provider</h2><p class="muted">查看其凭据池或新增真实模型。</p></template></section></section><section class="surface"><div class="section-title"><div><h2>直接模型目录</h2><p class="muted">模型名全局唯一；团队和调用方均使用此名称。</p></div><el-button type="primary" @click="openModel()">新增真实模型</el-button></div><el-table :data="models"><el-table-column prop="modelName" label="模型名"/><el-table-column prop="providerName" label="Provider"/><el-table-column label="输入/百万 Token"><template #default="scope">{{ scope.row.inputPricePerMillion }} {{ scope.row.currency }}</template></el-table-column><el-table-column label="输出/百万 Token"><template #default="scope">{{ scope.row.outputPricePerMillion }} {{ scope.row.currency }}</template></el-table-column><el-table-column label="状态"><template #default="scope"><el-tag :type="scope.row.enabled ? 'success' : 'info'">{{ scope.row.enabled ? '启用' : '停用' }}</el-tag></template></el-table-column><el-table-column label="操作" width="130"><template #default="scope"><el-button text @click="openModel(scope.row)">编辑</el-button><el-button text type="danger" @click="removeModel(scope.row)">删除</el-button></template></el-table-column></el-table></section><el-dialog v-model="dialog" :title="dialog === 'provider' ? (editingProvider ? '编辑 Provider' : '新增 Provider') : dialog === 'credential' ? '新增 Provider API Key' : editingModel ? '编辑真实模型' : '新增真实模型'" width="520px"><el-form v-if="dialog === 'provider'" label-position="top"><el-form-item label="名称"><el-input v-model="providerForm.name"/></el-form-item><el-form-item label="类型"><el-select v-model="providerForm.providerType"><el-option label="OpenAI Compatible" value="OPENAI_COMPATIBLE"/><el-option label="Mock OpenAI" value="MOCK_OPENAI"/></el-select></el-form-item><el-form-item v-if="providerForm.providerType === 'OPENAI_COMPATIBLE'" label="Base URL"><el-input v-model="providerForm.baseUrl" placeholder="https://provider.example.com/v1"/></el-form-item><el-switch v-model="providerForm.enabled" active-text="启用" inactive-text="停用"/></el-form><el-form v-else-if="dialog === 'credential'" label-position="top"><el-form-item label="凭据名称"><el-input v-model="credentialForm.name"/></el-form-item><el-form-item label="API Key"><el-input v-model="credentialForm.apiKey" show-password autocomplete="off"/></el-form-item><el-alert type="warning" :closable="false" title="明文只在提交时使用；服务端仅保存 AES-GCM 密文和末四位。"/></el-form><el-form v-else label-position="top"><el-form-item label="Provider"><el-select v-model="modelForm.providerId"><el-option v-for="provider in providers" :key="provider.providerId" :label="provider.name" :value="provider.providerId"/></el-select></el-form-item><el-form-item label="真实模型名"><el-input v-model="modelForm.modelName" placeholder="gpt-4o"/></el-form-item><el-form-item label="输入价格/百万 Token"><el-input-number v-model="modelForm.inputPricePerMillion" :min="0"/></el-form-item><el-form-item label="输出价格/百万 Token"><el-input-number v-model="modelForm.outputPricePerMillion" :min="0"/></el-form-item></el-form><template #footer><el-button @click="dialog = null">取消</el-button><el-button type="primary" @click="dialog === 'provider' ? saveProvider() : dialog === 'credential' ? saveCredential() : saveModel()">保存</el-button></template></el-dialog></section></template>
